"""
MKT Christ Commentary — Job chapters 39–41
Run: python3 scripts/zc-christ-job-39-41.py

Ch 39 (30v): YHWH's animal kingdom speeches — all creation as testimony to the wisdom
    of the Logos through whom all things were made (John 1:3; Col 1:16). Each creature's
    design reflects the Wisdom incarnate (1 Cor 1:30; Col 2:3); the war horse (vv19-25)
    anticipates the rider on the white horse (Rev 19:11-16).
Ch 40 (24v): YHWH's first challenge + Job's submission + Behemoth — Rom 9:20 answers
    vv1-2 (who contends with God?); the creature solidarity of v15 ("made with you")
    typifies the Incarnation (Phil 2:7; John 1:14); Behemoth as chief of God's works
    mirrors Christ as firstborn of all creation (Col 1:15).
Ch 41 (34v): Leviathan — the primordial chaos-serpent whom only Christ can bind
    (Matt 12:29); Heb 2:14 (destroying the one who has power of death); Col 2:15
    (triumphing over rulers and authorities); Rev 20:2 (Satan bound). The king over
    all sons of pride (v34) is dethroned by the King of kings (Rev 19:16).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "39": {
    "1": "<p>YHWH&rsquo;s opening question about the mountain goats and hinds giving birth establishes the fundamental christological frame of the divine speeches: the Creator has intimate knowledge of and care for every creature he made. Col 1:16: &ldquo;by him all things were created, in heaven and on earth, visible and invisible.&rdquo; The God who attends the wild birth of mountain goats in remote ranges is the God who became one of his creatures at Bethlehem &mdash; the Incarnation is the ultimate expression of Creator-attentiveness to creaturely life.</p>",
    "2": "<p>Counting the months of wild pregnancy &mdash; the divine arithmetic of creaturely gestation. Matt 10:29: &ldquo;are not two sparrows sold for a penny? And not one of them will fall to the ground apart from your Father.&rdquo; The sparrow-accounting is the NT echo of the mountain-goat-accounting; Christ reveals that divine attention to creaturely life is not a peripheral attribute of God but belongs to the Father&rsquo;s character that the Son makes known (John 1:18: &ldquo;the only God, who is at the Father&rsquo;s side, he has made him known&rdquo;).</p>",
    "3": "<p>The wild creatures bringing forth their young and delivering their offspring &mdash; the drama of wild birth without human attendance. John 16:21: &ldquo;when a woman is giving birth, she has sorrow because her hour has come, but when she has delivered the baby, she no longer remembers the anguish, for joy that a human being has been born into the world.&rdquo; Christ uses the birth metaphor to describe the eschatological labor of the church; the wild creature&rsquo;s unattended birth is also the type of Christ&rsquo;s own birth in the manger, without the attendance of palace or physician.</p>",
    "4": "<p>Their young becoming strong and going out, leaving and not returning &mdash; the natural independence of wild offspring. John 8:36: &ldquo;if the Son sets you free, you will be free indeed.&rdquo; The freedom of the wild creature that grows up and departs is the type of the freedom that Christ brings: the children of God, set free by the Son, are not confined to the structures of the old creation&rsquo;s bondage but go out into the freedom Christ won.</p>",
    "5": "<p>Who has let the wild donkey (onager) go free? Who has loosed the bonds of the swift donkey? &mdash; the untamed freedom of the wild ass. Rom 8:20&ndash;21: &ldquo;for the creation was subjected to futility, not willingly, but because of him who subjected it, in hope that the creation itself will be set free from its bondage to corruption and obtain the freedom of the glory of the children of God.&rdquo; The wild donkey&rsquo;s freedom from human bondage is a foretaste of creation&rsquo;s eschatological liberation that Christ&rsquo;s redemption inaugurates.</p>",
    "6": "<p>YHWH making the wilderness the wild donkey&rsquo;s home and the salt land its dwelling &mdash; the hostile desert as habitat, not prison. Luke 4:1: &ldquo;Jesus, full of the Holy Spirit, returned from the Jordan and was led by the Spirit in the wilderness for forty days.&rdquo; Christ in the wilderness does not flee the hostile environment but inhabits it as the new Adam who will not yield to the tempter. The salt-land as home for the wild free creature is the type of Christ dwelling in the desert of human suffering.</p>",
    "7": "<p>The wild donkey scorning the city&rsquo;s tumult and not hearing the driver&rsquo;s shout &mdash; radical independence from human control. John 18:36: &ldquo;my kingdom is not of this world. If my kingdom were of this world, my servants would have been fighting.&rdquo; Christ refuses the political kingdom offered by the tempter (Luke 4:5&ndash;8) and scorns the city&rsquo;s attempt to make him king by force (John 6:15). The wild donkey&rsquo;s independence from city-tumult is the type of Christ&rsquo;s kingdom that operates by different logic than earthly power.</p>",
    "8": "<p>The wild donkey ranging the hills as pasture, searching for every green thing &mdash; the sovereign freedom of creaturely provision. Matt 6:26: &ldquo;look at the birds of the air: they neither sow nor reap nor gather into barns, and yet your heavenly Father feeds them.&rdquo; The wild donkey&rsquo;s hill-ranging for food is the type of the Father&rsquo;s provision for those who, like Christ, prioritize the kingdom and trust the Father for daily sustenance.</p>",
    "9": "<p>Will the wild ox serve you or spend the night at your manger? &mdash; the untameable re&rsquo;em defying domestic service. Phil 2:7: &ldquo;taking the form of a servant (<em>doulos</em>, a slave), being born in the likeness of men.&rdquo; The wild ox that refuses the manger is the anti-type of Christ who voluntarily went to a manger (Luke 2:7) &mdash; not in servitude to human power but in the voluntary self-lowering of the Incarnation. The untameable God became tameable in the only way that matters: through love, not compulsion.</p>",
    "10": "<p>Can you bind the wild ox in the furrow or will it harrow the valleys after you? &mdash; the impossibility of harnessing untamed power for human work. Eph 1:19&ndash;20: &ldquo;the immeasurable greatness of his power toward us who believe, according to the working of his great might that he worked in Christ when he raised him from the dead.&rdquo; The power that cannot be bound in a furrow is the power that raised Christ from the dead and is now working in those who are in him.</p>",
    "11": "<p>Will you rely on the wild ox&rsquo;s great strength and leave your labor to it? &mdash; the folly of depending on undomesticated power. John 15:5: &ldquo;I am the vine; you are the branches. Whoever abides in me and I in him, he it is that bears much fruit, for apart from me you can do nothing.&rdquo; The labor that cannot be left to the untameable wild ox can be entrusted to Christ, the Vine, who transmits his life to the branches and bears fruit through those connected to him.</p>",
    "12": "<p>Will the wild ox bring your grain home and gather it to your threshing floor? &mdash; the wild animal that will not harvest for the human economy. Matt 3:12: &ldquo;his winnowing fork is in his hand, and he will clear his threshing floor and gather his wheat into the barn.&rdquo; Christ, not a wild animal, is the one who gathers the harvest: the gathering to the heavenly barn is not entrusted to untameable creaturely force but to the Son who comes in judgment to gather his own.</p>",
    "13": "<p>The ostrich&rsquo;s wing flapping joyfully &mdash; the wing of feathers without the stork&rsquo;s wisdom or care. In the wisdom hierarchy of Job 38&ndash;39, the ostrich is notable as the creature from whom wisdom is specifically withheld (v17). In the NT, wisdom is specifically concentrated and given: 1 Cor 1:30 (&ldquo;Christ Jesus, who became to us wisdom from God&rdquo;); Col 2:3 (&ldquo;in whom are hidden all the treasures of wisdom and knowledge&rdquo;). The creature that lacks wisdom is the anti-type of Christ who is wisdom itself.</p>",
    "14": "<p>The ostrich leaving her eggs in the ground for the earth to warm them &mdash; the strange parenting inversion. Isa 49:15: &ldquo;can a woman forget her nursing child, that she should have no compassion on the son of her womb? Even these may forget, yet I will not forget you.&rdquo; The ostrich&rsquo;s apparently careless maternal behavior highlights by contrast the divine maternal tenderness that reaches its fullest expression in Christ: &ldquo;Jerusalem, Jerusalem&hellip;how often would I have gathered your children together as a hen gathers her brood under her wings&rdquo; (Matt 23:37).</p>",
    "15": "<p>The ostrich forgetting that a foot may crush the eggs or a wild beast trample them &mdash; creaturely vulnerability without protective wisdom. John 10:28: &ldquo;I give them eternal life, and they will never perish, and no one will snatch them out of my hand.&rdquo; The eggs left unprotected on the ground are the anti-type of Christ&rsquo;s sheep who are held in his hand and the Father&rsquo;s hand &mdash; double protection that no foot can trample.</p>",
    "16": "<p>The ostrich dealing harshly with her young as though they were not hers &mdash; the maternal-inversion creature. Lam 4:3: &ldquo;even jackals offer the breast; they nurse their young, but the daughter of my people has become cruel, like the ostriches in the wilderness.&rdquo; The cruel city and the ostrich-mother are the backdrop for the tender father-figure of Christ: &ldquo;see what kind of love the Father has given to us, that we should be called children of God&rdquo; (1 John 3:1). The maternal rejection that the ostrich embodies is the opposite of the Incarnation&rsquo;s embrace.</p>",
    "17": "<p>&ldquo;God has made her forget wisdom and has not given her a share in understanding&rdquo; &mdash; wisdom withheld from the ostrich by divine sovereign distribution. 1 Cor 1:27: &ldquo;God chose what is foolish in the world to shame the wise.&rdquo; The sovereign distribution of wisdom &mdash; withheld from the ostrich, poured out through the Spirit on the disciples at Pentecost (Acts 2:17) &mdash; is the divine prerogative. The wisdom denied to the ostrich is the wisdom given to the weak and foolish in Christ (1 Cor 2:12).</p>",
    "18": "<p>When the ostrich rouses herself and runs, she laughs at the horse and rider &mdash; the compensation of speed for lack of wisdom. 1 Cor 1:25: &ldquo;the foolishness of God is wiser than men, and the weakness of God is stronger than horses.&rdquo; The ostrich&rsquo;s speed surpassing horse and rider is the type of the divine wisdom that appears foolish (the cross) but outruns every human wisdom-strategy. The laughing ostrich is the type of the God who holds the wise in derision (Ps 2:4) and whose apparent foolishness triumphs.</p>",
    "19": "<p>&ldquo;Do you give the horse his might? Do you clothe his neck with a mane?&rdquo; &mdash; YHWH as the source of the war horse&rsquo;s power. Rev 19:11: &ldquo;then I saw heaven opened, and behold, a white horse! The one sitting on it is called Faithful and True, and in righteousness he judges and makes war.&rdquo; The war horse&rsquo;s divine-given might is the animal type; the white horse of the parousia is the eschatological fulfillment. Christ is both the giver of the horse&rsquo;s might and the rider of the heavenly horse at the final battle.</p>",
    "20": "<p>Making the war horse leap like the locust, its majestic snorting striking terror &mdash; the awesome power of the battle horse. Joel 2:4&ndash;5: &ldquo;their appearance is like the appearance of horses, and like war horses they run&hellip;like the rumbling of chariots on the tops of mountains.&rdquo; The locust-horse of Joel&rsquo;s prophecy and the horses of Rev 9:7 are the eschatological escalation of Job 39&rsquo;s war horse: the divine power displayed in creation is concentrated in the final eschatological battle where Christ leads the armies of heaven.</p>",
    "21": "<p>Pawing in the valley, exulting in strength, going out to meet weapons &mdash; the war horse&rsquo;s fearless eagerness. Heb 12:2: &ldquo;looking to Jesus, the founder and perfecter of our faith, who for the joy that was set before him endured the cross.&rdquo; The war horse that goes out to meet weapons without fear is the type of Christ going to the cross &ldquo;for the joy set before him&rdquo; &mdash; not retreating from the weapons of suffering and death but meeting them directly.</p>",
    "22": "<p>Laughing at fear and not being dismayed, not turning back from the sword &mdash; the courage of the war horse. John 10:18: &ldquo;no one takes it [my life] from me, but I lay it down of my own accord.&rdquo; The war horse that does not flinch from the sword is the type of Christ who set his face toward Jerusalem (Luke 9:51) and went voluntarily to the death that would accomplish redemption. The fearlessness is not ignorance of danger but sovereign willingness to face it.</p>",
    "23": "<p>The quiver rattling against the horse, the spear and javelin flashing &mdash; the instruments of war that the courageous horse ignores. Isa 53:5: &ldquo;he was pierced for our transgressions; he was crushed for our iniquities.&rdquo; The spear that the war horse faces was literally planted in Christ&rsquo;s side at Golgotha (John 19:34). The weapons that the horse faces bravely are the instruments of Christ&rsquo;s passion; the war horse&rsquo;s courage typifies the courage of the Servant who did not turn from the smiting (Isa 50:6).</p>",
    "24": "<p>Swallowing the ground with fierceness and rage, not standing still at the trumpet&rsquo;s sound &mdash; the war horse&rsquo;s total commitment at the charge. Rev 19:14&ndash;15: &ldquo;the armies of heaven, arrayed in fine linen, white and pure, were following him on white horses. From his mouth comes a sharp sword with which to strike down the nations.&rdquo; The war horse&rsquo;s absolute commitment at the battle charge finds its fullest expression in Christ leading the armies of heaven in the final decisive battle against evil.</p>",
    "25": "<p>&ldquo;Ha!&rdquo; the horse says at the trumpet sound; smelling the battle from afar, the thunder of captains and the shouting &mdash; the war horse&rsquo;s instinct for conflict. 1 Thess 4:16: &ldquo;the Lord himself will descend from heaven with a cry of command, with the voice of an archangel, and with the sound of the trumpet of God.&rdquo; The trumpet that sends the war horse charging is the type of the trumpet that heralds Christ&rsquo;s parousia &mdash; the divine battle-call that sets in motion the final overthrow of all that opposes the kingdom.</p>",
    "26": "<p>&ldquo;Is it by your understanding that the hawk soars and spreads his wings toward the south?&rdquo; &mdash; the hawk&rsquo;s migratory instinct beyond human teaching. Deut 32:11: &ldquo;like an eagle that stirs up its nest, that flutters over its young, spreading out its wings, catching them, bearing them on its pinions.&rdquo; God as eagle-parent is the OT background for Christ gathering Jerusalem&rsquo;s children under his wings (Matt 23:37). The soaring hawk typifies the divine pastoral care that watches over and gathers the vulnerable.</p>",
    "27": "<p>&ldquo;Is it at your command that the eagle mounts up and makes his nest on high?&rdquo; &mdash; the eagle&rsquo;s ascent beyond human command. Eph 4:10: &ldquo;he who descended is the one who also ascended far above all the heavens, that he might fill all things.&rdquo; The eagle ascending to make its nest on high is the type of Christ&rsquo;s ascension: he who descended (the Incarnation) is the one who ascended &ldquo;far above all the heavens.&rdquo; The eagle&rsquo;s high nest is the type of the session at the Father&rsquo;s right hand.</p>",
    "28": "<p>The eagle dwelling on the rock, making its stronghold on the rocky crag &mdash; the impregnable height of the eagle&rsquo;s refuge. Matt 16:18: &ldquo;on this rock I will build my church, and the gates of hell shall not prevail against it.&rdquo; The eagle&rsquo;s rocky stronghold is the type of the church built on Christ the rock &mdash; equally impregnable from below. 1 Cor 10:4: &ldquo;that rock was Christ&rdquo; &mdash; the rock that the eagle inhabits is the rock that is Christ himself.</p>",
    "29": "<p>From the height the eagle spies out the prey, its eyes seeing from afar &mdash; the eagle&rsquo;s panoramic vision. Heb 4:13: &ldquo;no creature is hidden from God&rsquo;s sight, but all are naked and exposed to the eyes of him to whom we must give account.&rdquo; Rev 1:14: &ldquo;his eyes were like a flame of fire&rdquo; &mdash; the eyes of the risen Christ that see from afar. The eagle&rsquo;s far-seeing eyes from the high crag are the type of Christ&rsquo;s all-seeing gaze from the Father&rsquo;s right hand.</p>",
    "30": "<p>The eagle&rsquo;s young ones suck up blood, and where the slain are, there is the eagle &mdash; the eagle as gatherer at the place of death. Matt 24:28: &ldquo;wherever the corpse is, there the vultures will gather.&rdquo; This sign of judgment (the gathering of scavengers at the place of death) is Christ&rsquo;s own sign for the parousia&rsquo;s irreversible judgment. Rev 19:17&ndash;18: the angel calls the birds to the great supper of God where the dead of the final battle are consumed. The eagle at the slain is the sign of final divine judgment executed by Christ.</p>"
  },
  "40": {
    "1": "<p>YHWH&rsquo;s first challenge: &ldquo;shall a faultfinder contend with the Almighty?&rdquo; &mdash; the direct question that puts Job&rsquo;s legal claim to the test. Rom 9:20: &ldquo;who are you, O man, to answer back to God? Will what is molded say to its molder, &lsquo;why have you made me like this?&rsquo;&rdquo; The challenge to the faultfinder is answered in the NT not by human silence alone but by Christ&rsquo;s perfect advocacy: only the one who himself made no fault (1 Pet 2:22) could properly plead before God. Job&rsquo;s silence (v4&ndash;5) anticipates the silence of all accusation before Christ&rsquo;s perfect righteousness.</p>",
    "2": "<p>He who argues with God, let him answer &mdash; the demand for a real legal response. In the NT, the one who argues with God from a position of genuine righteousness is Christ himself: Heb 5:7 (&ldquo;in the days of his flesh, Jesus offered up prayers and supplications, with loud cries and tears, to him who was able to save him from death&rdquo;). Christ argues with God not from self-justification but from perfect prayer and submission; his cry of dereliction (Matt 27:46) is the deepest legal argument ever made before God, and the resurrection is God&rsquo;s answer.</p>",
    "3": "<p>Job answers YHWH and says &mdash; the moment of the creature&rsquo;s response before the Creator. This structural moment (creature speaking to Creator after the divine speeches) has its NT parallel in every prayer: the creature who has heard the Creator&rsquo;s self-revelation in Christ now speaks in response. Eph 2:18: &ldquo;through him [Christ] we both have access in one Spirit to the Father.&rdquo; Job&rsquo;s answer is the model of creaturely response: from within the overwhelming encounter, with diminished argument but with genuine address.</p>",
    "4": "<p>&ldquo;Behold, I am of small account; what shall I answer you? I lay my hand on my mouth&rdquo; &mdash; the silencing of the creature before the Creator. Phil 2:10&ndash;11: &ldquo;at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue confess that Jesus Christ is Lord.&rdquo; The silenced mouth that lays its hand before God in Job 40:4 is the prototype of the universal confession before Christ at the parousia; the creature&rsquo;s recognition of its smallness before the divine reaches its fullest expression in the acknowledgment of Christ&rsquo;s lordship.</p>",
    "5": "<p>Once I have spoken and will not answer, twice and will add nothing more &mdash; the economy of the humbled creature&rsquo;s speech. Matt 6:7: &ldquo;when you pray, do not heap up empty phrases as the Gentiles do.&rdquo; Luke 18:13: the tax collector who would not even lift his eyes but simply said &ldquo;God, be merciful to me, a sinner.&rdquo; Job&rsquo;s silenced brevity is the model of genuine prayer: not the accumulation of legal arguments but the honest acknowledgment of creatureliness before God, which is itself an approach to the prayer that Christ teaches.</p>",
    "6": "<p>YHWH answering Job from the whirlwind a second time &mdash; the second divine speech. The double divine address from the storm is the structure of divine revelation: the first address is the question that humbles; the second address is the deeper revelation that heals. In the NT, the double speaking of the Father at Jesus&rsquo; baptism (Matt 3:17) and transfiguration (Matt 17:5) follows the same pattern of progressive divine revelation that discloses the Son more fully in the second address.</p>",
    "7": "<p>Gird up your loins like a man; I will question you and you make it known &mdash; the renewed call to courageous encounter. 1 Pet 1:13: &ldquo;preparing your minds for action (<em>lit.</em> girding up the loins of your mind), being sober-minded, set your hope fully on the grace that will be brought to you at the revelation of Jesus Christ.&rdquo; The loins-girding that YHWH demands of Job in the storm becomes, in the NT, the mental preparation for the parousia. The courageous encounter with God is now undertaken through hope in Christ&rsquo;s revelation.</p>",
    "8": "<p>&ldquo;Will you even put me in the wrong? Will you condemn me that you may be in the right?&rdquo; &mdash; the sharpest question of the divine speeches. Rom 3:4: &ldquo;let God be true though every one were a liar, as it is written, &lsquo;that you may be justified in your words, and prevail when you are judged.&rsquo;&rdquo; Paul quotes Ps 51:4 here; the question that YHWH poses to Job &mdash; will you condemn God to justify yourself? &mdash; is answered by the gospel in the opposite direction: God justifies the sinner at the cost of condemning his own Son (Rom 8:3).</p>",
    "9": "<p>Do you have an arm like God&rsquo;s, can you thunder with a voice like his? &mdash; the question of divine power. Rev 1:15: &ldquo;his voice was like the roar of many waters.&rdquo; The thundering divine voice of the whirlwind is the voice of the risen Christ in Revelation. The divine power (arm, voice, thunder) that only God possesses is the power that Christ shares with the Father (John 10:30: &ldquo;I and the Father are one&rdquo;; John 5:19: &ldquo;whatever the Father does, the Son does likewise&rdquo;).</p>",
    "10": "<p>Adorn yourself with majesty and dignity, clothe yourself with glory and splendor &mdash; the call to put on divine royal attributes. Phil 2:9&ndash;11: God has highly exalted Christ and given him the name above every name. The divine majesty, dignity, glory, and splendor that Job cannot clothe himself in are the very attributes that Christ shares from eternity and puts back on at his exaltation after the cross. 1 Tim 6:16: &ldquo;who alone has immortality, who dwells in unapproachable light.&rdquo;</p>",
    "11": "<p>Pour out the overflowings of your anger; look on everyone who is proud and abase him &mdash; the divine prerogative to judge the proud. Jas 4:6: &ldquo;God opposes the proud but gives grace to the humble.&rdquo; Luke 1:52: &ldquo;he has brought down the mighty from their thrones and exalted those of humble estate.&rdquo; The divine prerogative to abase the proud that Job cannot exercise is the prerogative that Christ&rsquo;s cross and parousia exercise definitively: the cross humbles the proud by revealing that no human achievement merits justification; the parousia abases every earthly pride before the returning King.</p>",
    "12": "<p>Look on everyone who is proud and bring him low; tread down the wicked where they stand &mdash; the divine judgment that Job cannot execute. John 5:22: &ldquo;the Father judges no one, but has given all judgment to the Son.&rdquo; Acts 17:31: God &ldquo;has fixed a day on which he will judge the world in righteousness by a man whom he has appointed.&rdquo; The judgment of the proud and wicked that YHWH challenges Job to execute is the judgment that the Father has given to Christ: the Son will tread down the wicked at the appointed day.</p>",
    "13": "<p>Hide them all in the dust together; bind their faces in the world below &mdash; the disposal of the condemned. Rev 20:14&ndash;15: &ldquo;then Death and Hades were thrown into the lake of fire. This is the second death.&rdquo; The dust-binding and Sheol-binding that YHWH describes as his judicial prerogative is the prerogative that Christ exercises at the final judgment: the disposal of all that opposes the kingdom is the divine act committed to the Son (1 Cor 15:25: &ldquo;he must reign until he has put all his enemies under his feet&rdquo;).</p>",
    "14": "<p>&ldquo;Then will I also praise you, for your own right hand can save you&rdquo; &mdash; the ironic conditional: if Job can execute universal judgment, then God will acknowledge Job&rsquo;s self-sufficiency. The right hand that saves in the OT is YHWH&rsquo;s (Ps 98:1: &ldquo;his right hand and his holy arm have worked salvation for him&rdquo;); in the NT, the right hand is Christ&rsquo;s position (Heb 1:3: &ldquo;he sat down at the right hand of the Majesty on high&rdquo;) after accomplishing the salvation that no human right hand could achieve.</p>",
    "15": "<p>&ldquo;Look at Behemoth, which I made as I made you&rdquo; &mdash; the creature solidarity of Behemoth and Job, both made by the same Creator. Phil 2:7: &ldquo;taking the form of a servant, being born in the likeness of men.&rdquo; The &ldquo;made as I made you&rdquo; &mdash; creaturely solidarity between the powerful and the vulnerable &mdash; is the OT type of the Incarnation: the eternal Son took on the same creaturely status (&ldquo;likeness of men&rdquo;) as those he came to redeem. The Creator becoming a creature is the supreme expression of the solidarity that v15 implies.</p>",
    "16": "<p>His strength is in his loins, his power in the muscles of his belly &mdash; Behemoth&rsquo;s physical power concentrated in the body&rsquo;s core. Eph 6:10: &ldquo;be strong in the Lord and in the strength of his might.&rdquo; The strength of Behemoth that no human warrior can match is the strength that Christ makes available to those in him &mdash; not through physical might but through the Spirit: &ldquo;strengthened with power through his Spirit in your inner being&rdquo; (Eph 3:16). The interior power that Behemoth displays externally, Christ supplies inwardly to the believer.</p>",
    "17": "<p>His tail moves like a cedar, the sinews of his thighs are knit together &mdash; the extraordinary strength of Behemoth&rsquo;s body structure. 1 Cor 15:44: &ldquo;it is sown a natural body; it is raised a spiritual body.&rdquo; The resurrection body that Christ was first to receive (v20: &ldquo;the firstfruits&rdquo;) is the perfection of creaturely embodiment: the glorified body that Behemoth&rsquo;s extraordinary physicality faintly typifies. Christ&rsquo;s resurrection body is the first example of the new creation&rsquo;s embodied power (Phil 3:21: &ldquo;he will transform our lowly body to be like his glorious body&rdquo;).</p>",
    "18": "<p>His bones are tubes of bronze, his limbs like bars of iron &mdash; the impenetrable body of Behemoth. Acts 2:24: &ldquo;God raised him up, loosing the pangs of death, because it was not possible for him to be held by it.&rdquo; The bronze-bone, iron-limbed Behemoth that nothing can pierce is the creaturely type of Christ&rsquo;s resurrection body that death could not hold. The &ldquo;pangs of death&rdquo; that could not contain Christ are the force that Behemoth&rsquo;s impenetrable frame defies at a creaturely level.</p>",
    "19": "<p>&ldquo;He is the first of the works of God; let him who made him bring near his sword&rdquo; &mdash; Behemoth as the chief of the works of creation, challengeable only by his Maker. Col 1:15: &ldquo;he is the image of the invisible God, the firstborn of all creation.&rdquo; Behemoth as &ldquo;first of the works of God&rdquo; (re&rsquo;shit) is the creaturely type of Christ as &ldquo;firstborn of all creation&rdquo; (<em>prototokos</em>) &mdash; not the first creature made but the one who holds primacy over all creation. Only the Maker can bring the sword to Behemoth; only the cross could accomplish what creation could not.</p>",
    "20": "<p>The mountains yield their produce for him; all the wild beasts play where he lies &mdash; Behemoth as the center of the natural order. John 1:3: &ldquo;all things were made through him, and without him was not any thing made that was made.&rdquo; The Behemoth that the natural world serves and gathers around is the creaturely type of Christ as the one through whom all things exist and toward whom all things ultimately move (Rom 11:36: &ldquo;from him and through him and to him are all things&rdquo;).</p>",
    "21": "<p>Under the lotus plants he lies, in the shelter of the reeds and in the marsh &mdash; Behemoth resting in the wetlands. John 1:14: &ldquo;the Word became flesh and dwelt (<em>eskenosen</em>, tented/tabernacled) among us.&rdquo; The great creature resting in the marsh&rsquo;s shelter is the type of the Son taking his place in creaturely habitat. Christ who &ldquo;tabernacled&rdquo; among humanity rested in the specific ecological conditions of the Jordan valley and the reed-edged Sea of Galilee &mdash; the same terrain Behemoth inhabits.</p>",
    "22": "<p>The lotus trees cover him for shade; the willows of the brook surround him &mdash; the natural canopy over Behemoth. Ps 91:4: &ldquo;he will cover you with his pinions, and under his wings you will find refuge.&rdquo; The shade-giving lotus over Behemoth is the type of the divine covering over those who take refuge in God. Matt 23:37: the hen covering chicks under wings is Christ&rsquo;s own image for his protection of Jerusalem. The Behemoth shaded in the marsh becomes, by inversion, the one who provides shade and protection for others.</p>",
    "23": "<p>If the river is turbulent he is not frightened; he is confident though Jordan rushes against his mouth &mdash; Behemoth&rsquo;s confidence in the Jordan&rsquo;s rushing flood. Matt 3:13&ndash;17: Christ&rsquo;s baptism in the Jordan River. The Jordan that Behemoth is not frightened by is the Jordan in which Christ was baptized &mdash; identifying with sinners under judgment and emerging to the Father&rsquo;s declaration: &ldquo;this is my beloved Son, with whom I am well pleased.&rdquo; The confident creature in the Jordan typifies Christ&rsquo;s confident submission to baptismal waters of judgment.</p>",
    "24": "<p>Can one take him by his eyes or pierce his nose with a snare? &mdash; the unhuntable Behemoth. Luke 11:22: the &ldquo;stronger man&rdquo; who comes upon the strong man and overcomes him takes his armor and divides the spoil. Behemoth cannot be caught; but the &ldquo;stronger man&rdquo; of Christ&rsquo;s parable points to the one who can overcome the unhuntable &mdash; by going through death and resurrection rather than by conventional conquest. What no human snare can capture, the cross and resurrection accomplished.</p>"
  },
  "41": {
    "1": "<p>&ldquo;Can you draw out Leviathan with a fishhook?&rdquo; &mdash; the opening challenge of the Leviathan speech. Matt 12:29: &ldquo;how can someone enter a strong man&rsquo;s house and plunder his goods, unless he first binds the strong man?&rdquo; Leviathan, the primordial chaos-serpent, is the &ldquo;strong man&rdquo; that no human fisher can hook. Christ is the only one who can draw out and bind Leviathan &mdash; not through superior creaturely force but through the victory of the cross (Col 2:15: &ldquo;disarming the rulers and authorities and putting them to open shame, triumphing over them in him&rdquo;).</p>",
    "2": "<p>Can you put a rope in his nose or pierce his jaw with a hook? &mdash; the impossibility of controlling the sea-monster. Isa 27:1: &ldquo;in that day the LORD with his hard and great and strong sword will punish Leviathan the fleeing serpent, Leviathan the twisting serpent, and he will slay the dragon that is in the sea.&rdquo; The hook that no creature can drive through Leviathan&rsquo;s jaw is wielded by YHWH in the eschatological day; in the NT this is identified with Christ&rsquo;s final victory: Rev 20:2 (&ldquo;he seized the dragon, that ancient serpent, who is the devil and Satan, and bound him&rdquo;).</p>",
    "3": "<p>Will Leviathan speak with soft words to you, will he make a covenant with you? &mdash; the impossibility of diplomacy with the chaos-monster. Heb 2:14: &ldquo;since therefore the children share in flesh and blood, he himself likewise partook of the same things, that through death he might destroy the one who has the power of death, that is, the devil.&rdquo; Leviathan does not make covenants on human terms; Christ did not negotiate with death but destroyed it by undergoing it. The new covenant that Christ makes is not a diplomatic arrangement with the serpent but the serpent&rsquo;s defeat.</p>",
    "4": "<p>Will he make a covenant with you to be taken as a servant forever? &mdash; the impossibility of taming Leviathan for perpetual service. Rev 20:3: Satan &ldquo;bound&hellip;so that he might not deceive the nations any longer, until the thousand years were ended.&rdquo; The permanent taming of Leviathan that no human can accomplish is the accomplished fact of Christ&rsquo;s victory: the ancient serpent will be not only bound but cast into the lake of fire (Rev 20:10), permanently removed from his role as deceiver.</p>",
    "5": "<p>Will you play with Leviathan as with a bird, or put him on a leash for your girls? &mdash; the absurdity of treating the chaos-monster as a pet. Col 2:15: &ldquo;he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him.&rdquo; The enemies of creation that could never be made into pets are put to open shame by the cross: their power is publicly displayed as defeated. What appears to be Leviathan&rsquo;s triumph at the cross is the place where Christ &ldquo;put them to open shame.&rdquo;</p>",
    "6": "<p>Will traders make a bargain for him, will they divide him up among the merchants? &mdash; the economic impossibility of commercializing the chaos-monster. 1 Pet 1:18&ndash;19: &ldquo;you were ransomed from the futile ways inherited from your forefathers, not with perishable things such as silver or gold, but with the precious blood of Christ, like that of a lamb without blemish or spot.&rdquo; No merchant can bargain for Leviathan; but Christ paid the ransom that no commercial transaction could accomplish &mdash; not silver or gold but his own blood.</p>",
    "7": "<p>Can you fill his hide with harpoons or his head with fish spears? &mdash; the piercing of the impenetrable hide. Zech 12:10: &ldquo;they will look on me, on him whom they have pierced.&rdquo; John 19:34: &ldquo;one of the soldiers pierced his side with a spear, and at once blood and water came out.&rdquo; The impenetrable Leviathan whom no spear can pierce is the anti-type of Christ whose side was pierced &mdash; the one who was vulnerable to the very weapon that cannot reach the chaos-serpent. Christ absorbed the wound that Leviathan is immune to.</p>",
    "8": "<p>&ldquo;Lay your hands on him; remember the battle; you will not do it again!&rdquo; &mdash; the fearful warning against trying to fight Leviathan. Heb 2:14&ndash;15: &ldquo;that through death he might destroy the one who has the power of death&hellip;and deliver all those who through fear of death were subject to lifelong slavery.&rdquo; Those enslaved by the fear of death-in-battle with Leviathan &mdash; never daring to lay hands on him &mdash; are set free by Christ who fought and destroyed death on their behalf. The warning of v8 is the freedom of those liberated by Christ&rsquo;s vicarious battle.</p>",
    "9": "<p>Behold, any hope of overcoming Leviathan is false; at the sight of him one is cast down &mdash; the hopelessness of the creature before the chaos-monster. Rom 7:24: &ldquo;wretched man that I am! Who will deliver me from this body of death?&rdquo; The hopelessness that any human faces against Leviathan is the spiritual despair of the one who cannot defeat the power of sin and death through self-effort. The answer: v25: &ldquo;thanks be to God through Jesus Christ our Lord!&rdquo; &mdash; the deliverer who overcomes where all human hope is false.</p>",
    "10": "<p>No one is so fierce that he would dare to stir up Leviathan &mdash; the universal creaturely fear. Rev 5:3&ndash;5: &ldquo;no one in heaven or on earth or under the earth was able to open the scroll&hellip;the Lion of the tribe of Judah, the Root of David, has conquered.&rdquo; The scroll that no creature can open and the Leviathan that no creature dares stir are the same problem: the deficiency of all creaturely power before the ultimate challenge. The Lamb who takes the scroll is the Christ who alone dared to stir Leviathan &mdash; and conquered.</p>",
    "11": "<p>&ldquo;Who has first given to me, that I should repay him? Whatever is under the whole heaven is mine&rdquo; &mdash; the divine ownership of all things, pre-empting any human claim on God. Rom 11:35&ndash;36: &ldquo;or who has given a gift to him that he might be repaid? For from him and through him and to him are all things.&rdquo; Paul quotes this very logic in his doxology concluding the argument for divine sovereignty in salvation. The divine ownership that YHWH asserts over Leviathan is the ownership that Christ shares: John 17:10: &ldquo;all mine are yours, and yours are mine.&rdquo;</p>",
    "12": "<p>&ldquo;I will not keep silence concerning his limbs, or his mighty strength, or his goodly frame&rdquo; &mdash; YHWH speaking fully about Leviathan&rsquo;s design. John 1:1: &ldquo;in the beginning was the Word.&rdquo; The divine speech that brings Leviathan&rsquo;s frame into existence and describes it is the same divine Word through whom all things were made (John 1:3). The Creator who speaks Leviathan&rsquo;s limbs into being is the Logos; the thorough divine description of the chaos-monster is itself an act of sovereign lordship over it.</p>",
    "13": "<p>Who can strip off his outer garment, who can penetrate his double coat of mail? &mdash; the impenetrable armor of Leviathan. Eph 6:11&ndash;13: &ldquo;put on the whole armor of God, that you may be able to stand against the schemes of the devil.&rdquo; The armor that covers the enemy and makes him invulnerable to creaturely attack is defeated by Christ&rsquo;s own armor of divine righteousness. The spiritual armor of God (6:14&ndash;17) is the equipment Christ provides to stand against the Leviathan-enemy whose own armor no human penetrates.</p>",
    "14": "<p>Who can open the doors of his face, around his teeth is terror &mdash; the terrifying mouth of Leviathan. Rev 12:9: &ldquo;the great dragon was thrown down, that ancient serpent, who is called the devil and Satan, the deceiver of the whole world.&rdquo; Rev 20:2: &ldquo;he seized the dragon, that ancient serpent.&rdquo; The terrifying mouth of the chaos-serpent is the mouth of the dragon whom Christ, the one who holds &ldquo;the keys of Death and Hades&rdquo; (Rev 1:18), has authority to bind and cast into the lake of fire.</p>",
    "15": "<p>His back is made of rows of shields, shut up closely as with a seal &mdash; the sealed armor of Leviathan. Matt 27:66: the tomb of Christ was &ldquo;made secure by sealing the stone and setting a guard.&rdquo; The sealed armor that no creature can penetrate is the ironic type of the sealed tomb that could not hold Christ. The same sealing that makes Leviathan impenetrable made the tomb &ldquo;secure&rdquo; &mdash; and Christ passed through it in resurrection. The seal that defends Leviathan became the seal that Christ defeated on Easter morning.</p>",
    "16": "<p>Each of them is joined to the next; no air can come between them &mdash; the seamless armor of the chaos-monster. John 19:23&ndash;24: Christ&rsquo;s tunic was &ldquo;seamless, woven in one piece from top to bottom.&rdquo; The seamless tunic that the soldiers would not divide by lot is a type of Christ&rsquo;s priesthood: Heb 7:24 (&ldquo;he holds his priesthood permanently, because he continues forever&rdquo;). The seamlessness of Leviathan&rsquo;s armor is the grotesque anti-type of Christ&rsquo;s unbroken, undivided priesthood and perfect integrity.</p>",
    "17": "<p>They are joined one to another; they clasp each other and cannot be separated &mdash; the inseparability of Leviathan&rsquo;s armor. Rom 8:38&ndash;39: &ldquo;neither death nor life, nor angels nor rulers&hellip;will be able to separate us from the love of God in Christ Jesus our Lord.&rdquo; The inseparable union of Leviathan&rsquo;s scales is the anti-type of the inseparable union between Christ and those who are his. What holds Leviathan together in menace, holds believers in safety: nothing can separate from Christ&rsquo;s love.</p>",
    "18": "<p>His sneezings flash forth light, and his eyes are like the eyelids of the dawn &mdash; Leviathan&rsquo;s eyes like the dawn. Rev 1:16: &ldquo;his face was like the sun shining in full strength.&rdquo; Rev 2:28; 22:16: Christ as &ldquo;the bright morning star.&rdquo; Leviathan&rsquo;s dawn-eyes are the terrible parody of Christ&rsquo;s radiant face and morning-star identity. The light associated with the chaos-monster is the counterfeit of the light that Christ is (John 8:12: &ldquo;I am the light of the world&rdquo;).</p>",
    "19": "<p>Out of his mouth go flaming torches; sparks of fire leap out &mdash; the fire-breathing of Leviathan. Acts 2:3: &ldquo;divided tongues as of fire appeared to them and rested on each one of them.&rdquo; The fire from Leviathan&rsquo;s mouth is the destructive anti-type of the Spirit&rsquo;s fire at Pentecost. Both are fire from a mouth; the first destroys, the second purifies and empowers. Christ sends the Spirit&rsquo;s fire not as Leviathan breathes destructive flame but as the Baptizer with the Holy Spirit and fire (Matt 3:11).</p>",
    "20": "<p>Out of his nostrils comes smoke as from a boiling pot and burning rushes &mdash; the smoke and steam of Leviathan. Rev 9:2&ndash;3: smoke from the pit darkening the sun; the locust-horses with smoke from their mouths. The smoke of the chaos-monster becomes, in Revelation&rsquo;s eschatological vision, the smoke of the abyss &mdash; demonic powers released for the final judgment. Rev 8:4: &ldquo;the smoke of the incense, with the prayers of the saints, rose before God from the hand of the angel.&rdquo; The smoke of Leviathan has its countertype in the incense-smoke of the saints&rsquo; prayers ascending to God through Christ&rsquo;s high-priestly intercession.</p>",
    "21": "<p>His breath kindles coals, and a flame comes forth from his mouth &mdash; Leviathan as living fire-source. Heb 12:29: &ldquo;our God is a consuming fire.&rdquo; The fire that belongs to God is the fire from which Leviathan&rsquo;s breath is derived: the chaos-monster has a derived, creaturely version of the divine fire. Christ, who is one with the Father (John 10:30), participates in the divine fire that is ultimately not destructive for those in him but purifying: &ldquo;he will baptize you with the Holy Spirit and fire&rdquo; (Matt 3:11).</p>",
    "22": "<p>In his neck abides strength, and terror dances before him &mdash; the power and terror of Leviathan. Col 1:13: &ldquo;he has delivered us from the domain of darkness and transferred us to the kingdom of his beloved Son.&rdquo; The terror that dances before Leviathan is the terror of the domain of darkness from which Christ transfers those who are his. The power in Leviathan&rsquo;s neck is the power of the dark domain; Christ&rsquo;s kingdom transfer removes believers from that terror&rsquo;s dominion.</p>",
    "23": "<p>The folds of his flesh stick together, firm on him and immovable &mdash; Leviathan&rsquo;s impenetrable body. John 10:18: &ldquo;no one takes [my life] from me, but I lay it down of my own accord.&rdquo; The immovable flesh of Leviathan is the grotesque anti-type of Christ&rsquo;s voluntary self-offering. Leviathan cannot be moved because of impenetrable power; Christ cannot be taken against his will because of sovereign love. Both are &ldquo;immovable&rdquo; in their flesh, but for opposite reasons &mdash; one from creaturely armor, one from divine sovereign love.</p>",
    "24": "<p>His heart is hard as stone, hard as the lower millstone &mdash; the stone-hard heart of the chaos-monster. Ezek 36:26: &ldquo;I will remove the heart of stone from your flesh and give you a heart of flesh.&rdquo; The stone-heart of Leviathan is the ultimate expression of the stone-heart that God removes through the new covenant. Christ&rsquo;s crucified heart &mdash; pierced by a soldier&rsquo;s spear (John 19:34), yielding blood and water (the signs of the sacraments) &mdash; is the opposite of Leviathan&rsquo;s stone-heart.</p>",
    "25": "<p>When he raises himself up the mighty are afraid; at the crashing they are beside themselves &mdash; the universal fear of Leviathan. Rev 6:15&ndash;16: at the wrath of the Lamb, &ldquo;the kings of the earth and the great ones and the generals and the rich and the powerful, and everyone, slave and free, hid themselves in the caves and among the rocks of the mountains.&rdquo; The terror that Leviathan&rsquo;s rising produces is the terror that the day of Christ&rsquo;s wrath will produce &mdash; universal, without class distinction, overwhelming even the mighty.</p>",
    "26": "<p>Though the sword reaches him it does not avail; nor the spear, the dart, or the javelin &mdash; the weapons that cannot harm Leviathan. Eph 6:16: &ldquo;the shield of faith, with which you can extinguish all the flaming darts of the evil one.&rdquo; The weapons that cannot reach Leviathan have their countertype in the flaming darts of the enemy that Christ&rsquo;s armor absorbs. The armor of God (6:13&ndash;17) is the specific equipment that transforms the helplessness before Leviathan&rsquo;s weapon-immunity into a protected ability to stand.</p>",
    "27": "<p>He counts iron as straw and bronze as rotten wood &mdash; the contempt Leviathan has for weapons. 1 Cor 1:18: &ldquo;the word of the cross is folly to those who are perishing, but to us who are being saved it is the power of God.&rdquo; The weapons that Leviathan dismisses as straw are the weapons that Christ&rsquo;s opponents dismiss &mdash; the apparent weakness of the cross. But the cross that looks like straw to worldly power is the weapon that actually defeats the ultimate enemy.</p>",
    "28": "<p>The arrow cannot make Leviathan flee; slingstones turn to stubble for him &mdash; projectile weapons failing against the monster. Luke 10:19: &ldquo;behold, I have given you authority to tread on serpents and scorpions, and over all the power of the enemy, and nothing shall hurt you.&rdquo; The disciples&rsquo; authority over serpents and the enemy&rsquo;s power is the delegated authority of Christ who overcame the ultimate serpent. The arrows that fail against Leviathan fail in human hands; in Christ&rsquo;s authority, the power of the enemy is overcome.</p>",
    "29": "<p>Clubs are counted as stubble; he laughs at the rattle of javelins &mdash; Leviathan&rsquo;s contemptuous power. Luke 11:22: &ldquo;when one stronger than he attacks him and overcomes him, he takes away his armor in which he trusted.&rdquo; Leviathan laughs at the javelins of the weak; the stronger one who overcomes him does not come with superior javelins but with a different kind of power &mdash; the cross and resurrection. The armor in which the strong man (Leviathan/the devil) trusted is taken away not by bigger weapons but by Christ&rsquo;s unique victory.</p>",
    "30": "<p>His underparts are like sharp potsherds; he spreads himself like a threshing sledge on the mire &mdash; Leviathan leaving destruction in his wake. Isa 41:15: &ldquo;behold, I make of you a threshing sledge, new, sharp, and having teeth; you shall thresh the mountains and crush them.&rdquo; Isaiah applies the threshing-sledge image to Israel; Christ applies the threshing motif to himself: John 15:2 (&ldquo;every branch that does bear fruit he prunes&rdquo;). The destructive wake of Leviathan has its redemptive countertype in Christ&rsquo;s pruning that produces fruit.</p>",
    "31": "<p>He makes the deep boil like a pot; he makes the sea like a pot of ointment &mdash; Leviathan churning the sea. Rev 21:1: &ldquo;the sea was no more.&rdquo; The boiling sea that Leviathan stirs is permanently calmed in the new creation. Christ&rsquo;s first display of authority over the sea (Matt 8:26&ndash;27: &ldquo;even the winds and the sea obey him&rdquo;) is the firstfruits of the new creation&rsquo;s perfect calm. The sea Leviathan boils is the sea Christ calms; the new creation&rsquo;s &ldquo;sea was no more&rdquo; is the final calming after Leviathan&rsquo;s permanent defeat.</p>",
    "32": "<p>Behind him he leaves a shining wake; one would think the deep had white hair &mdash; Leviathan&rsquo;s luminous trail. Rev 1:14: &ldquo;the hairs of his head were white, like white wool, like snow.&rdquo; The white-haired Ancient of Days imagery in Revelation belongs to the risen Christ. Leviathan&rsquo;s white wake in the deep sea is the subverted type of Christ&rsquo;s white-haired glory in the vision of John. What Leviathan&rsquo;s passage leaves as a churning wake, Christ&rsquo;s resurrection leaves as permanent transformed reality.</p>",
    "33": "<p>&ldquo;On earth there is not his like, a creature without fear&rdquo; &mdash; Leviathan&rsquo;s incomparability on earth. Col 1:18&ndash;19: &ldquo;he is the head of the body, the church. He is the beginning, the firstborn from the dead, that in everything he might be preeminent. For in him all the fullness of God was pleased to dwell.&rdquo; The incomparable creature on earth has its countertype in the incomparable Christ who is not merely the greatest creature but the fullness of God dwelling in creaturely form. Leviathan has no equal among creatures; Christ is the Creator who became a creature.</p>",
    "34": "<p>&ldquo;He sees everything that is high; he is king over all the sons of pride&rdquo; &mdash; Leviathan as the king of the proud. Rev 19:16: &ldquo;on his robe and on his thigh he has a name written, King of kings and Lord of lords.&rdquo; The king of the sons of pride is dethroned by the King of kings. 1 Cor 15:25: &ldquo;he must reign until he has put all his enemies under his feet.&rdquo; The final enemy (death) is put under Christ&rsquo;s feet after the cross and resurrection; Leviathan&rsquo;s kingship over pride is superseded by Christ&rsquo;s kingship over all &mdash; the kingdom given to him by the Father (1 Cor 15:28).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'job')
    merge_comm(existing, CHRIST)
    save_comm('mkt-christ', 'job', existing)
    total = sum(len(vv) for vv in CHRIST.values())
    parts = ', '.join(f'ch{ch}={len(CHRIST[ch])}' for ch in sorted(CHRIST, key=int))
    print(f'Job 39-41 mkt-christ: {total} verses written ({parts}).')

if __name__ == '__main__':
    main()
